package edu.dyds.trips.domain.usecase

import edu.dyds.trips.domain.entity.Result
import edu.dyds.trips.domain.entity.Trip
import edu.dyds.trips.domain.repository.TripsRepository
import kotlinx.coroutines.test.runTest
import org.junit.Before
import org.junit.Test
import kotlin.test.assertEquals
import kotlin.test.assertTrue

class DeleteTripUseCaseTest {
    private lateinit var fakeRepository: FakeTripsRepository
    private lateinit var useCase: DeleteTripUseCase

    @Before
    fun setup() {
        fakeRepository = FakeTripsRepository()
        useCase = DeleteTripUseCaseImpl(fakeRepository)
    }

    @Test
    fun `invoke should return Success when trip deleted`() = runTest {
        // Arrange
        val tripId = "trip-123"
        fakeRepository.setResult(Result.Success(Unit))

        // Act
        val result = useCase(tripId)

        // Assert
        assertTrue(result is Result.Success)
    }

    @Test
    fun `invoke should return Failure when trip not found`() = runTest {
        // Arrange
        val tripId = "nonexistent-id"
        val exception = Exception("Trip not found")
        fakeRepository.setResult(Result.Failure(exception))

        // Act
        val result = useCase(tripId)

        // Assert
        assertTrue(result is Result.Failure)
    }

    @Test
    fun `invoke should return Failure on repository error`() = runTest {
        // Arrange
        val tripId = "trip-123"
        val exception = Exception("Database error")
        fakeRepository.setResult(Result.Failure(exception))

        // Act
        val result = useCase(tripId)

        // Assert
        assertTrue(result is Result.Failure)
    }

    @Test
    fun `invoke should call repository with correct trip id`() = runTest {
        // Arrange
        val tripId = "trip-456"
        fakeRepository.setResult(Result.Success(Unit))

        // Act
        val result = useCase(tripId)

        // Assert
        assertTrue(result is Result.Success)
        assertEquals(fakeRepository.lastDeletedTripId, tripId)
    }
}

private class FakeTripsRepository : TripsRepository {
    private var result: Result<Unit> = Result.Success(Unit)
    var lastDeletedTripId: String? = null

    fun setResult(newResult: Result<Unit>) {
        result = newResult
    }

    override suspend fun getTrips(): Result<List<Trip>> =
        Result.Success(emptyList())

    override suspend fun getTripById(id: String): Result<Trip?> =
        Result.Success(null)

    override suspend fun saveTrip(trip: Trip): Result<Unit> =
        Result.Success(Unit)

    override suspend fun updateTrip(trip: Trip): Result<Unit> =
        Result.Success(Unit)

    override suspend fun deleteTrip(id: String): Result<Unit> {
        lastDeletedTripId = id
        return result
    }
}

package edu.dyds.trips.domain.usecase

import edu.dyds.trips.domain.entity.Country
import edu.dyds.trips.domain.entity.Currency
import edu.dyds.trips.domain.entity.Result
import edu.dyds.trips.domain.repository.CountriesRepository
import kotlinx.coroutines.test.runTest
import org.junit.Before
import org.junit.Test
import kotlin.test.assertEquals
import kotlin.test.assertTrue

class GetCountriesUseCaseTest {
    private lateinit var fakeRepository: FakeCountriesRepository
    private lateinit var useCase: GetCountriesUseCase

    @Before
    fun setup() {
        fakeRepository = FakeCountriesRepository()
        useCase = GetCountriesUseCaseImpl(fakeRepository)
    }

    @Test
    fun `invoke should return Success with countries list`() = runTest {
        // Arrange
        val countries = listOf(
            createMockCountry("AR", "Argentina"),
            createMockCountry("BR", "Brazil")
        )
        fakeRepository.setResult(Result.Success(countries))

        // Act
        val result = useCase()

        // Assert
        assertTrue(result is Result.Success)
        assertEquals((result as Result.Success).value, countries)
    }

    @Test
    fun `invoke should return Failure on exception`() = runTest {
        // Arrange
        val exception = Exception("Network error")
        fakeRepository.setResult(Result.Failure(exception))

        // Act
        val result = useCase()

        // Assert
        assertTrue(result is Result.Failure)
        assertEquals((result as Result.Failure).exception.message, "Network error")
    }
}

private class FakeCountriesRepository : CountriesRepository {
    private var result: Result<List<Country>> = Result.Success(emptyList())

    fun setResult(newResult: Result<List<Country>>) {
        result = newResult
    }

    override suspend fun getCountries(): Result<List<Country>> = result

    override suspend fun searchCountries(query: String): Result<List<Country>> =
        Result.Success(emptyList())

    override suspend fun getCountryByCode(code: String): Result<Country> =
        Result.Success(createMockCountry(code, "Test"))
}

private fun createMockCountry(code: String, name: String): Country = Country(
    code = code,
    name = name,
    officialName = "$name Official",
    region = "Americas",
    subregion = "South America",
    capital = "Capital",
    currencies = mapOf("CUR" to Currency("CUR", "Currency", "C")),
    languages = mapOf("es" to "Spanish"),
    timezones = listOf("UTC-03:00"),
    latitude = -34.6037,
    longitude = -58.3816,
    flagUrl = "https://example.com/flag.png",
    population = 1000000
)

package edu.dyds.trips.domain.usecase

import edu.dyds.trips.domain.entity.Country
import edu.dyds.trips.domain.entity.CountryDetail
import edu.dyds.trips.domain.entity.Currency
import edu.dyds.trips.domain.entity.Result
import edu.dyds.trips.domain.repository.CountriesRepository
import kotlinx.coroutines.test.runTest
import org.junit.Before
import org.junit.Test
import kotlin.test.assertEquals
import kotlin.test.assertNotNull
import kotlin.test.assertTrue

class GetCountryDetailsUseCaseTest {
    private lateinit var fakeRepository: FakeCountriesRepository
    private lateinit var useCase: GetCountryDetailsUseCase

    @Before
    fun setup() {
        fakeRepository = FakeCountriesRepository()
        useCase = GetCountryDetailsUseCaseImpl(fakeRepository)
    }

    @Test
    fun `invoke should return Success with CountryDetail`() = runTest {
        // Arrange
        val country = createMockCountry("AR", "Argentina")
        fakeRepository.setCountryByCodeResult(Result.Success(country))

        // Act
        val result = useCase("AR")

        // Assert
        assertTrue(result is Result.Success)
        val detail = (result as Result.Success).value
        assertNotNull(detail)
        assertEquals(detail.country.code, "AR")
        assertEquals(detail.weatherForecast.size, 0)
    }

    @Test
    fun `invoke should return Failure when country not found`() = runTest {
        // Arrange
        val exception = Exception("Country not found")
        fakeRepository.setCountryByCodeResult(Result.Failure(exception))

        // Act
        val result = useCase("XX")

        // Assert
        assertTrue(result is Result.Failure)
    }

    @Test
    fun `invoke should populate country and empty weather forecast`() = runTest {
        // Arrange
        val country = createMockCountry("BR", "Brazil")
        fakeRepository.setCountryByCodeResult(Result.Success(country))

        // Act
        val result = useCase("BR")

        // Assert
        assertTrue(result is Result.Success)
        val detail = (result as Result.Success).value
        assertEquals(detail.country.name, "Brazil")
        assertTrue(detail.weatherForecast.isEmpty())
    }
}

private class FakeCountriesRepository : CountriesRepository {
    private var countryByCodeResult: Result<Country> = Result.Success(
        createMockCountry("XX", "Test")
    )

    fun setCountryByCodeResult(result: Result<Country>) {
        countryByCodeResult = result
    }

    override suspend fun getCountries(): Result<List<Country>> =
        Result.Success(emptyList())

    override suspend fun searchCountries(query: String): Result<List<Country>> =
        Result.Success(emptyList())

    override suspend fun getCountryByCode(code: String): Result<Country> =
        countryByCodeResult
}

private fun createMockCountry(code: String, name: String): Country = Country(
    code = code,
    name = name,
    officialName = "$name Official",
    region = "Americas",
    subregion = "South America",
    capital = "Capital",
    currencies = mapOf("CUR" to Currency("CUR", "Currency", "C")),
    languages = mapOf("es" to "Spanish"),
    timezones = listOf("UTC-03:00"),
    latitude = -34.6037,
    longitude = -58.3816,
    flagUrl = "https://example.com/flag.png",
    population = 1000000
)

