    override suspend fun updateTrip(trip: Trip): Result<Unit> =
        Result.Success(Unit)

    override suspend fun deleteTrip(id: String): Result<Unit> =
        Result.Success(Unit)
}

private fun createMockTrip(code: String, name: String): Trip = Trip(
    countryCode = code,
