package edu.dyds.trips.domain.usecase

import edu.dyds.trips.domain.entity.Result
import edu.dyds.trips.domain.entity.WeatherForecast
import edu.dyds.trips.domain.repository.WeatherRepository
import kotlinx.coroutines.test.runTest
import org.junit.Before
import org.junit.Test
import kotlin.test.assertEquals
import kotlin.test.assertTrue

class GetWeatherForecastUseCaseTest {
    private lateinit var fakeRepository: FakeWeatherRepository
    private lateinit var useCase: GetWeatherForecastUseCase

    @Before
    fun setup() {
        fakeRepository = FakeWeatherRepository()
        useCase = GetWeatherForecastUseCaseImpl(fakeRepository)
    }

    @Test
    fun `invoke should return Success with weather forecast list`() = runTest {
        // Arrange
        val forecast = listOf(
            createMockForecast("2026-06-11"),
            createMockForecast("2026-06-12")
        )
        fakeRepository.setResult(Result.Success(forecast))

        // Act
        val result = useCase(latitude = -34.6037, longitude = -58.3816)

        // Assert
        assertTrue(result is Result.Success)
        assertEquals((result as Result.Success).value.size, 2)
        assertEquals((result as Result.Success).value[0].date, "2026-06-11")
    }

    @Test
    fun `invoke should return Success with empty list when no forecast available`() = runTest {
        // Arrange
        fakeRepository.setResult(Result.Success(emptyList()))

        // Act
        val result = useCase(latitude = 0.0, longitude = 0.0)

        // Assert
        assertTrue(result is Result.Success)
        assertEquals((result as Result.Success).value.size, 0)
    }

    @Test
    fun `invoke should return Failure on network error`() = runTest {
        // Arrange
        val exception = Exception("Network error")
        fakeRepository.setResult(Result.Failure(exception))

        // Act
        val result = useCase(latitude = -34.6037, longitude = -58.3816)

        // Assert
        assertTrue(result is Result.Failure)
    }

    @Test
    fun `invoke should pass correct coordinates to repository`() = runTest {
        // Arrange
        val latitude = 40.7128
        val longitude = -74.0060
        fakeRepository.setResult(Result.Success(emptyList()))

        // Act
        val result = useCase(latitude = latitude, longitude = longitude)

        // Assert
        assertEquals(fakeRepository.lastLatitude, latitude)
        assertEquals(fakeRepository.lastLongitude, longitude)
    }
}

private class FakeWeatherRepository : WeatherRepository {
    private var result: Result<List<WeatherForecast>> = Result.Success(emptyList())
    var lastLatitude: Double = 0.0
    var lastLongitude: Double = 0.0

    fun setResult(newResult: Result<List<WeatherForecast>>) {
        result = newResult
    }

    override suspend fun getWeatherForecast(
        latitude: Double,
        longitude: Double
    ): Result<List<WeatherForecast>> {
        lastLatitude = latitude
        lastLongitude = longitude
        return result
    }
}

private fun createMockForecast(date: String): WeatherForecast = WeatherForecast(
    date = date,
    tempMinCelsius = 15.0,
    tempMaxCelsius = 25.0,
    precipitationMm = 0.0,
    windSpeedKmh = 10.0,
    weatherCode = 0,
    description = "Sunny"
)

package edu.dyds.trips.domain.usecase

import edu.dyds.trips.domain.entity.Result
import edu.dyds.trips.domain.entity.Trip
import edu.dyds.trips.domain.repository.TripsRepository
import kotlinx.coroutines.test.runTest
import org.junit.Before
import org.junit.Test
import kotlin.test.assertEquals
import kotlin.test.assertTrue

class SaveTripUseCaseTest {
    private lateinit var fakeRepository: FakeTripsRepository
    private lateinit var useCase: SaveTripUseCase

    @Before
    fun setup() {
        fakeRepository = FakeTripsRepository()
        useCase = SaveTripUseCaseImpl(fakeRepository)
    }

    @Test
    fun `invoke should return Success when trip saved`() = runTest {
        // Arrange
        val trip = createMockTrip("AR", "Argentina", "2026-07-01", "2026-07-15")
        fakeRepository.setResult(Result.Success(Unit))

        // Act
        val result = useCase(trip)

        // Assert
        assertTrue(result is Result.Success)
    }

    @Test
    fun `invoke should return Failure when start date after end date`() = runTest {
        // Arrange
        val trip = createMockTrip("AR", "Argentina", "2026-07-15", "2026-07-01")

        // Act
        val result = useCase(trip)

        // Assert
        assertTrue(result is Result.Failure)
        assertTrue((result as Result.Failure).exception.message?.contains("Start date") == true)
    }

    @Test
    fun `invoke should accept trip with same start and end date`() = runTest {
        // Arrange
        val trip = createMockTrip("AR", "Argentina", "2026-07-01", "2026-07-01")
        fakeRepository.setResult(Result.Success(Unit))

        // Act
        val result = useCase(trip)

        // Assert
        assertTrue(result is Result.Success)
    }

    @Test
    fun `invoke should return Failure on repository error`() = runTest {
        // Arrange
        val trip = createMockTrip("AR", "Argentina", "2026-07-01", "2026-07-15")
        val exception = Exception("Database error")
        fakeRepository.setResult(Result.Failure(exception))

        // Act
        val result = useCase(trip)

        // Assert
        assertTrue(result is Result.Failure)
    }

    @Test
    fun `invoke should call repository with correct trip`() = runTest {
        // Arrange
        val trip = createMockTrip("BR", "Brazil", "2026-08-01", "2026-08-30")
        fakeRepository.setResult(Result.Success(Unit))

        // Act
        val result = useCase(trip)

        // Assert
        assertTrue(result is Result.Success)
        assertEquals(fakeRepository.lastSavedTrip?.countryCode, "BR")
    }
}

private class FakeTripsRepository : TripsRepository {
    private var result: Result<Unit> = Result.Success(Unit)
    var lastSavedTrip: Trip? = null

    fun setResult(newResult: Result<Unit>) {
        result = newResult
    }

    override suspend fun getTrips(): Result<List<Trip>> =
        Result.Success(emptyList())

    override suspend fun getTripById(id: String): Result<Trip?> =
        Result.Success(null)

    override suspend fun saveTrip(trip: Trip): Result<Unit> {
        lastSavedTrip = trip
        return result
    }

    override suspend fun updateTrip(trip: Trip): Result<Unit> =
        Result.Success(Unit)

    override suspend fun deleteTrip(id: String): Result<Unit> =
        Result.Success(Unit)
}

private fun createMockTrip(
    code: String,
    name: String,
    startDate: String,
    endDate: String
): Trip = Trip(
    countryCode = code,
    countryName = name,
    startDate = startDate,
    endDate = endDate
)

package edu.dyds.trips.domain.usecase

import edu.dyds.trips.domain.entity.Country
import edu.dyds.trips.domain.entity.Currency
import edu.dyds.trips.domain.entity.Result
import edu.dyds.trips.domain.repository.CountriesRepository
import kotlinx.coroutines.test.runTest
import org.junit.Before
import org.junit.Test
import kotlin.test.assertEquals
import kotlin.test.assertTrue

class SearchCountriesUseCaseTest {
    private lateinit var fakeRepository: FakeCountriesRepository
    private lateinit var useCase: SearchCountriesUseCase

    @Before
    fun setup() {
        fakeRepository = FakeCountriesRepository()
        useCase = SearchCountriesUseCaseImpl(fakeRepository)
    }

    @Test
    fun `invoke should return Success with countries list matching query`() = runTest {
        // Arrange
        val countries = listOf(createMockCountry("AR", "Argentina"))
        fakeRepository.setSearchResult(Result.Success(countries))

        // Act
        val result = useCase("Argentina")

        // Assert
        assertTrue(result is Result.Success)
        assertEquals((result as Result.Success).value.size, 1)
        assertEquals((result as Result.Success).value[0].name, "Argentina")
    }

    @Test
    fun `invoke should return Success with empty list when no matches`() = runTest {
        // Arrange
        fakeRepository.setSearchResult(Result.Success(emptyList()))

        // Act
        val result = useCase("NonExistent")

        // Assert
        assertTrue(result is Result.Success)
        assertEquals((result as Result.Success).value.size, 0)
    }

    @Test
    fun `invoke should return Failure on exception`() = runTest {
        // Arrange
        val exception = Exception("Search failed")
        fakeRepository.setSearchResult(Result.Failure(exception))

        // Act
        val result = useCase("Argentina")

        // Assert
        assertTrue(result is Result.Failure)
        assertEquals((result as Result.Failure).exception.message, "Search failed")
    }
}

private class FakeCountriesRepository : CountriesRepository {
    private var searchResult: Result<List<Country>> = Result.Success(emptyList())

    fun setSearchResult(newResult: Result<List<Country>>) {
        searchResult = newResult
    }

    override suspend fun getCountries(): Result<List<Country>> =
        Result.Success(emptyList())

    override suspend fun searchCountries(query: String): Result<List<Country>> =
        searchResult

    override suspend fun getCountryByCode(code: String): Result<Country> =
        Result.Success(createMockCountry(code, "Test"))
}

private fun createMockCountry(code: String, name: String): Country = Country(
