    officialName = "$name Official",
    region = "Americas",
    subregion = "South America",
    capital = "Capital",
    currencies = mapOf("CUR" to Currency("CUR", "Currency", "C")),
    languages = mapOf("es" to "Spanish"),
    timezones = listOf("UTC-03:00"),
    latitude = -34.6037,
    longitude = -58.3816,
    flagUrl = "https://example.com/flag.png",
    population = 1000000
)

